import subprocess
from pathlib import Path

def generate_requirements_txt():
    """
    Generate requirements.txt with hashes.
    
    This function generates a requirements.txt file with hashes to ensure 
    consistent dependencies across development and production environments.
    """
    try:
        # Use pip freeze to get all installed packages and their versions
        output = subprocess.check_output(['pip', 'freeze']).decode('utf-8')
        
        # Write the output to a requirements.txt file
        with open('requirements.txt', 'w') as f:
            for line in output.splitlines():
                f.write(line + '\n')
    except Exception as e:
        print(f"Error generating requirements.txt: {e}")

def update_pip_lockfile():
    """
    Update pip's lock file.
    
    This function updates the pip lock file to ensure consistent dependencies 
    across development and production environments.
    """
    try:
        # Use pip-compile to generate a lock file
        subprocess.check_call(['pip-compile'])
        
        # Move the generated lock file to the root directory
        Path('requirements.txt').rename(Path('requirements.lock'))
    except Exception as e:
        print(f"Error updating pip lockfile: {e}")

def update_poetry_lockfile():
    """
    Update Poetry's lock file.
    
    This function updates the Poetry lock file to ensure consistent dependencies 
    across development and production environments.
    """
    try:
        # Use poetry install to generate a lock file
        subprocess.check_call(['poetry', 'install'])
        
        # Move the generated lock file to the root directory
        Path('poetry.lock').rename(Path('pyproject.toml'))
    except Exception as e:
        print(f"Error updating Poetry lockfile: {e}")

def main():
    generate_requirements_txt()
    update_pip_lockfile()
    update_poetry_lockfile()

if __name__ == "__main__":
    main()